"pago","legacy_financial_transaction_id":"","created_at":"2025-08-30T20:02:24.329000","updated_at":"2025-08-30T20:02:24.329000","created_by":"lucassander.neteller@gmail.com"},{"legacy_installment_id":"68b34404079944be6672d294","legacy_service_order_id":"68b3433efd0a6637ec4145da","payment_method":"pix","notes":"","installment_number":"2","legacy_org_id":"","payment_date":"2025-08-30","installment_amount":"375","due_date":"2025-09-29","status":"pago","legacy_financial_transaction_id":"","created_at":"2025-08-30T18:33:40.889000","updated_at":"2025-08-30T18:34:21.143000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b34404f17983d050301bd8","legacy_service_order_id":"68b3433efd0a6637ec4145da","payment_method":"pix","notes":"","installment_number":"1","legacy_org_id":"","payment_date":"2025-08-30","installment_amount":"375","due_date":"2025-08-29","status":"pago","legacy_financial_transaction_id":"","created_at":"2025-08-30T18:33:40.549000","updated_at":"2025-08-30T18:33:40.549000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b338da9b76af5baa4c2afe","legacy_service_order_id":"68b3344bc0f3a3dcad62318b","payment_method":"pix","notes":"","installment_number":"3","legacy_org_id":"","payment_date":"","installment_amount":"98.33333333333333","due_date":"2025-10-29","status":"pendente","legacy_financial_transaction_id":"","created_at":"2025-08-30T17:46:02.620000","updated_at":"2025-08-30T17:46:02.620000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b338d9f23a3367110fecbd","legacy_service_order_id":"68b3344bc0f3a3dcad62318b","payment_method":"pix","notes":"","installment_number":"2","legacy_org_id":"","payment_date":"","installment_amount":"98.33333333333333","due_date":"2025-09-29","status":"pendente","legacy_financial_transaction_id":"","created_at":"2025-08-30T17:46:01.915000","updated_at":"2025-08-30T17:46:01.915000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b338d965f167b5128b76b4","legacy_service_order_id":"68b3344bc0f3a3dcad62318b","payment_method":"pix","notes":"","installment_number":"1","legacy_org_id":"","payment_date":"2025-08-30","installment_amount":"98.33333333333333","due_date":"2025-08-29","status":"pago","legacy_financial_transaction_id":"","created_at":"2025-08-30T17:46:01.577000","updated_at":"2025-08-30T17:46:01.577000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b32e60cee23df875275070","legacy_service_order_id":"68b322fbf17983d0502ed6ca","payment_method":"pix","notes":"","installment_number":"2","legacy_org_id":"","payment_date":"","installment_amount":"147.5","due_date":"2025-09-29","status":"pendente","legacy_financial_transaction_id":"","created_at":"2025-08-30T17:01:20.994000","updated_at":"2025-08-30T17:01:20.994000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b32e6090462226c115051a","legacy_service_order_id":"68b322fbf17983d0502ed6ca","payment_method":"pix","notes":"","installment_number":"1","legacy_org_id":"","payment_date":"2025-08-30","installment_amount":"147.5","due_date":"2025-08-29","status":"pago","legacy_financial_transaction_id":"","created_at":"2025-08-30T17:01:20.734000","updated_at":"2025-08-30T17:01:20.734000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b3279cd2f6405ee1130ac9","legacy_service_order_id":"68b325707125d85c774f07c1","payment_method":"dinheiro","notes":"","installment_number":"2","legacy_org_id":"","payment_date":"2025-08-30","installment_amount":"900","due_date":"2025-09-29","status":"pago","legacy_financial_transaction_id":"","created_at":"2025-08-30T16:32:28.506000","updated_at":"2025-08-30T17:03:47.093000","created_by":"beenkoficial@gmail.com"},{"legacy_installment_id":"68b3279c90462226c114c847","legacy_service_order_id":"68b325707125d85c774f07c1","payment_method":"dinheiro","notes":"","installment_number":"1","legacy_org_id":"","payment_date":"2025-08-30","installment_amount":"900","due_date":"2025-08-29","status":"pago","legacy_financial_transaction_id":"","created_at":"2025-08-30T16:32:28.164000","updated_at":"2025-08-30T16:32:28.164000","created_by":"beenkoficial@gmail.com"}]$installments$::jsonb) AS src(
    legacy_installment_id text,
    legacy_service_order_id text,
    payment_method text,
    notes text,
    installment_number text,
    legacy_org_id text,
    payment_date text,
    installment_amount text,
    due_date text,
    status text,
    legacy_financial_transaction_id text,
    created_at text,
    updated_at text,
    created_by text
  );


  WITH installment_rows AS (
    SELECT
      uuid_generate_v5(v_namespace, 'service_order_installment:' || src.legacy_installment_id) AS id,
      organizations.id AS organization_id,
      service_orders.id AS service_order_id,
      NULLIF(src.installment_number, '')::int AS installment_number,
      COALESCE(NULLIF(src.installment_amount, '')::numeric, 0) AS installment_amount,
      COALESCE(NULLIF(src.due_date, '')::date, NULLIF(src.created_at, '')::date, CURRENT_DATE) AS due_date,
      NULLIF(src.payment_date, '')::date AS payment_date,
      CASE src.status WHEN 'pago' THEN 'paid' WHEN 'vencido' THEN 'overdue' ELSE 'pending' END AS status,
      CASE src.payment_method
        WHEN 'pix' THEN 'pix'
        WHEN 'dinheiro' THEN 'cash'
        WHEN 'cartao_credito' THEN 'credit_card'
        WHEN 'cartao_debito' THEN 'debit_card'
        WHEN 'cheque' THEN 'check'
        WHEN 'boleto' THEN 'bank_slip'
        WHEN 'transferencia' THEN 'transfer'
        ELSE NULL
      END AS payment_method,
      NULLIF(src.notes, '') AS notes,
      COALESCE(NULLIF(src.created_at, '')::timestamptz, now()) AS created_at,
      NULLIF(src.created_by, '') AS created_by,
      COALESCE(NULLIF(src.updated_at, '')::timestamptz, NULLIF(src.created_at, '')::timestamptz, now()) AS updated_at,
      row_number() OVER (
        PARTITION BY service_orders.id, NULLIF(src.installment_number, '')::int
        ORDER BY COALESCE(NULLIF(src.updated_at, '')::timestamptz, NULLIF(src.created_at, '')::timestamptz, '-infinity'::timestamptz) DESC,
                 src.legacy_installment_id DESC
      ) AS rn
    FROM tmp_service_order_installment_source AS src
    JOIN public.organizations AS organizations
      ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    JOIN public.service_orders AS service_orders
      ON service_orders.id = uuid_generate_v5(v_namespace, 'service_order:' || src.legacy_service_order_id)
    WHERE src.legacy_org_id <> ''
      AND src.legacy_service_order_id <> ''
      AND src.installment_number <> ''
  )

  INSERT INTO public.service_order_installments (
    id, organization_id, service_order_id, installment_number, installment_amount,
    due_date, payment_date, status, payment_method, financial_transaction_id,
    notes, created_at, created_by, updated_at, updated_by, deleted_at, deleted_by
  )
  SELECT
    id, organization_id, service_order_id, installment_number, installment_amount,
    due_date, payment_date, status, payment_method, NULL,
    notes, created_at, created_by, updated_at, created_by, NULL, NULL
  FROM installment_rows
  WHERE rn = 1
  ON CONFLICT (service_order_id, installment_number) DO UPDATE
  SET
    installment_amount = EXCLUDED.installment_amount,
    due_date = EXCLUDED.due_date,
    payment_date = EXCLUDED.payment_date,
    status = EXCLUDED.status,
    payment_method = EXCLUDED.payment_method,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;


  RAISE NOTICE 'Skipped % service order installments without resolvable organization, service order, or number.', (
    SELECT count(*)
    FROM tmp_service_order_installment_source AS src
    LEFT JOIN public.organizations AS organizations
      ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    LEFT JOIN public.service_orders AS service_orders
      ON service_orders.id = uuid_generate_v5(v_namespace, 'service_order:' || src.legacy_service_order_id)
    WHERE src.legacy_org_id = ''
       OR src.legacy_service_order_id = ''
       OR src.installment_number = ''
       OR organizations.id IS NULL
       OR service_orders.id IS NULL
  );


END $$;